    #[test]
    fn test_bang_rms_norm_eps_resolved() {
        // Regression: f32 eps constant used to leak as "%epsf" into generated C.
        let mlir = r#"
module {
  llvm.func @tile_rms(%arg0: !llvm.ptr<1>, %arg1: !llvm.ptr<1>) attributes {hacc.entry} {
    ^bb0:
    %r = llvm.mlir.constant(8 : i32) : i32
    %c = llvm.mlir.constant(1024 : i32) : i32
    %eps = llvm.mlir.constant(1.0e-5 : f32) : f32
    %x = llvm.call @__tile_load_f32(%arg0, %r, %c) : (!llvm.ptr<1>, i32, i32) -> i32
    %y = llvm.call @__tile_rms_norm_f32(%x, %x, %eps, %r, %c) : (i32, i32, f32, i32, i32) -> i32
    llvm.call @__tile_store_f32(%arg1, %y, %r, %c) : (!llvm.ptr<1>, i32, i32, i32) -> ()
    llvm.return
  }
}
"#;
        let mlu = convert_mlir_to_bang(mlir).unwrap();
        assert!(!mlu.contains("%eps"), "eps SSA leaked:\n{}", mlu);
        assert!(mlu.contains("1.0e-5f"), "expected f32 eps literal:\n{}", mlu);
    }

