    #[test]
    fn test_bang_silu() {
        let mlu = convert_mlir_to_bang(silu_mlir()).unwrap();
        assert!(
            mlu.contains("__mlu_entry__ void tile_silu"),
            "missing silu kernel:\n{}",
            mlu
        );
        // Must negate x with __bang_mul_scalar -1.0f
        assert!(
            mlu.contains("__bang_mul_scalar") && mlu.contains("-1.0f"),
            "silu must negate x:\n{}",
            mlu
        );
        // Must use expf for exp(-x)
        assert!(
            mlu.contains("expf("),
            "silu must use expf for exp(-x):\n{}",
            mlu
        );
        // Must add 1.0 with __bang_add_scalar
        assert!(
            mlu.contains("__bang_add_scalar") && mlu.contains("1.0f"),
            "silu must add 1.0f:\n{}",
            mlu
        );
        // Must divide with __bang_div
        assert!(
            mlu.contains("__bang_div("),
            "silu must divide x by denom:\n{}",
            mlu
        );
        // 4-step comments
        assert!(mlu.contains("silu step 1"), "missing silu step 1:\n{}", mlu);
        assert!(mlu.contains("silu step 4"), "missing silu step 4:\n{}", mlu);
    }

